// Process: SC_THREAD run
// Static sensitivity: 

void mc_testbench::run() {
   testbench::enable_idle_sync_mode = false;
   testbench::idle_sync_stable_cycles = 1;
   testbench::a_in_data_ignore = false;
   testbench::a_in_data_skip = false;
   testbench::a_in_data_skip_quiet = false;
   testbench::a_in_data_skip_once = false;
   testbench::a_in_data_skip_noerr = false;
   testbench::a_in_data_array_comp_first = -1;
   testbench::a_in_data_array_comp_last = -1;
   testbench::a_in_data_wait_ctrl.clear();
   a_in_data_capture_count = 0;
   a_in_data_iteration_count = 0;
   testbench::b_in_data_ignore = false;
   testbench::b_in_data_skip = false;
   testbench::b_in_data_skip_quiet = false;
   testbench::b_in_data_skip_once = false;
   testbench::b_in_data_skip_noerr = false;
   testbench::b_in_data_array_comp_first = -1;
   testbench::b_in_data_array_comp_last = -1;
   testbench::b_in_data_wait_ctrl.clear();
   b_in_data_capture_count = 0;
   b_in_data_iteration_count = 0;
   testbench::valid_in_data_ignore = false;
   testbench::valid_in_data_skip = false;
   testbench::valid_in_data_skip_quiet = false;
   testbench::valid_in_data_skip_once = false;
   testbench::valid_in_data_skip_noerr = false;
   testbench::valid_in_data_array_comp_first = -1;
   testbench::valid_in_data_array_comp_last = -1;
   testbench::valid_in_data_wait_ctrl.clear();
   valid_in_data_capture_count = 0;
   valid_in_data_iteration_count = 0;
   testbench::result_ignore = false;
   testbench::result_skip = false;
   testbench::result_skip_quiet = false;
   testbench::result_skip_once = false;
   testbench::result_skip_noerr = false;
   testbench::result_array_comp_first = -1;
   testbench::result_array_comp_last = -1;
   testbench::result_use_mask = false;
   testbench::result_output_mask = ~0;
   testbench::result_wait_ctrl.clear();
   result_capture_count = 0;
   result_iteration_count = 0;
   testbench testbench_inst(sc_argc(), sc_argv());
   main_exit_code = testbench_inst.main();
   cout<<"Info: Execution of user-supplied C++ testbench 'main()' has completed with exit code = " << main_exit_code << endl;
   cout<<endl;
   cout<<"Info: Collecting data completed"<<endl;
   cout<<"   captured "<<a_in_data_capture_count<<" values of a_in_data"<<endl;
   cout<<"   captured "<<b_in_data_capture_count<<" values of b_in_data"<<endl;
   cout<<"   captured "<<valid_in_data_capture_count<<" values of valid_in_data"<<endl;
   cout<<"   captured "<<result_capture_count<<" values of result"<<endl;
   testbench_ended = true;
   testbench_end_event.notify(SC_ZERO_TIME);
}
